  /* ==== INICIO: COLA SIMPLE (FIFO) ==== */
  /* Cola enlazada:
     - offer(x): mete al final
     - poll(): saca del inicio
     - peek(): mira el inicio sin sacarlo
     - size/isEmpty: utilidades 
  */
  static final class Queue<T> {
    private static final class Node<T> {
      T v;
      Node<T> n;
      Node(T v) { this.v = v; }
    }

    private Node<T> head, tail;
    private int size = 0;

    void offer(T x) {
      Node<T> nn = new Node<>(x);
      if (tail == null) {
        head = tail = nn;
      } else {
        tail.n = nn;
        tail = nn;
      }
      size++;
    }

    T poll() {
      if (head == null) return null;
      T v = head.v;
      head = head.n;
      if (head == null) tail = null;
      size--;
      return v;
    }

    T peek() {
      return head == null ? null : head.v;
    }

    boolean isEmpty() {
      return size == 0;
    }

    int size() {
      return size;
    }
  }
   /* ==== FIN: COLA SIMPLE (FIFO) ==== */


  /* ==== INICIO: PILA AMBITOS (LIFO) usando 2 colas ==== */
  static final class Stack2Q<T> {
    private final Queue<T> q1 = new Queue<>();
    private final Queue<T> q2 = new Queue<>();

    void push(T x) {
      q2.offer(x);
      while (!q1.isEmpty()) {
        q2.offer(q1.poll());
      }
      while (!q2.isEmpty()) {
        q1.offer(q2.poll());
      }
    }

    T pop() {
      return q1.poll();
    }

    T peek() {
      return q1.peek();
    }

    boolean isEmpty() {
      return q1.isEmpty();
    }

    int size() {
      return q1.size();
    }
  }
