  /* ==== INICIO: MANEJADOR DE ÁMBITOS (PILA + BÚSQUEDA) ==== */
  /**
   * Maneja la pila de ámbitos con Stack2Q.
   * Nota importante:
   * - Como Stack2Q no permite iterar fácil,
   *   mantenemos un "mirror" (lista espejo) para poder buscar desde el scope más interno.
   * - scopeStack: estructura pedida (pila real).
   * - mirror: facilita resolve() (búsqueda de símbolos).
   */
  final class ScopeManager {
    private final Stack2Q<Scope> scopeStack = new Stack2Q<>();
    private final java.util.ArrayList<Scope> mirror = new java.util.ArrayList<>();

    /* ===== Entrar a un nuevo ámbito ===== */
    void enterScope() {
      Scope s = new Scope();
      scopeStack.push(s);
      mirror.add(s);
    }

    /* ===== Salir del ámbito actual ===== */
    void exitScope(Token where) {
      Scope popped = scopeStack.pop();
      if (popped == null) {
        semanticError(where, "Se intent\u00f3 cerrar un \u00e1mbito pero no hay \u00e1mbitos activos.");
        return;
      }
      /* Mantener sincronizado el espejo */
      if (!mirror.isEmpty()) {
        mirror.remove(mirror.size() - 1);
      }
    }

    /* ===== Scope actual (tope de la pila) ===== */
    private Scope current(Token where) {
      Scope s = scopeStack.peek();
      if (s == null) {
        semanticError(where, "No hay \u00e1mbito activo (scope stack vac\u00edo).");
      }
      return s;
    }

    /* ===== Declarar símbolo normal (VAR/CONST/PARAM) ===== */
    void declare(Token idTok, SymKind kind) {
      declareWithArity(idTok, kind, -1);
    }

    /* ===== Declarar función (FUNC) con aridad ===== */
    void declareFunc(Token idTok, int arity) {
      declareWithArity(idTok, SymKind.FUNC, arity);
    }

    /* ===== Declarar símbolo con tipo (VAR/CONST/PARAM) ===== */
    void declareTyped(Token idTok, SymKind kind, VType type) {
      declareWithArityTyped(idTok, kind, type, -1);
    }

    /* ===== Declarar función con tipo de retorno ===== */
    void declareFuncTyped(Token idTok, int arity, VType returnType) {
      declareWithArityTyped(idTok, SymKind.FUNC, returnType, arity);
    }

    private void declareWithArityTyped(Token idTok, SymKind kind, VType type, int arity) {
      Scope cur = current(idTok);
      if (cur == null) return;

      String name = idTok.image;

      if (cur.containsHere(name)) {
        SymbolInfo prev = cur.getHere(name);
        semanticError(idTok,
          "Redeclaraci\u00f3n de '" + name + "'. Ya declarado en l\u00ednea " +
          prev.declaredAt.beginLine + ", columna " + prev.declaredAt.beginColumn + "."
        );
        return;
      }

      cur.putHere(name, new SymbolInfo(name, kind, type, idTok, arity));
    }

    /* ===== Implementación común de declaración ===== */
    private void declareWithArity(Token idTok, SymKind kind, int arity) {
      Scope cur = current(idTok);
      if (cur == null) return;

      String name = idTok.image;

      if (cur.containsHere(name)) {
        SymbolInfo prev = cur.getHere(name);
        semanticError(idTok,
          "Redeclaraci\u00f3n de '" + name + "'. Ya declarado en l\u00ednea " +
          prev.declaredAt.beginLine + ", columna " + prev.declaredAt.beginColumn + "."
        );
        return;
      }
      /* Inserción en la tabla del scope actual */
      cur.putHere(name, new SymbolInfo(name, kind, VType.UNKNOWN, idTok, arity));
    }

    /* ===== Resolver: buscar símbolo desde el scope más interno hacia fuera ===== */
    SymbolInfo resolve(Token idTok) {
      String name = idTok.image;

      /* Buscar desde el final (scope más interno) hacia el inicio (global) */
      for (int i = mirror.size() - 1; i >= 0; i--) {
        SymbolInfo info = mirror.get(i).getHere(name);
        if (info != null) {
          if (isInitializing(idTok)) {
            semanticError(idTok, "No se puede usar '" + name + "' dentro de su propia inicializaci\u00f3n.");
          }
          return info;
        }
      }

      // Si ya se reportó como palabra reservada mal escrita, no spamear no declarado
      if (typoKeywords.contains(name)) {
        return null;
      }

      semanticError(idTok, "Uso de '" + name + "' pero no est\u00e1 declarado.");
      return null;
    }
  }
